# Plan: Add `next/geo` Utility Module

## Context

We're adding a new public `next/geo` entry point to the Next.js framework that provides geolocation helpers for middleware and edge functions. This follows the exact same three-file pattern used by existing entry points like `next/server` (which exposes `userAgent`/`userAgentFromString`).

The module will parse geolocation data from CDN/proxy headers (Vercel, Cloudflare), provide country name lookup, region matching, and Haversine distance calculation.

---

## Files to Create

### 1. Core Implementation: `packages/next/src/server/web/spec-extension/geo.ts`

**Pattern reference:** `packages/next/src/server/web/spec-extension/user-agent.ts`

Contents:

```typescript
/**
 * Geo interface representing geolocation data extracted from request headers.
 */
export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

/**
 * Map of ISO 3166-1 alpha-2 country codes to country names.
 * Includes at least 10 common codes.
 */
const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

/**
 * Extract geolocation from raw Headers object.
 * Reads Vercel geo headers, falls back to Cloudflare for countryCode.
 */
export function geoFromHeaders(headers: Headers): Geo {
  const city = headers.get('x-vercel-ip-city') || undefined
  const countryCode =
    headers.get('x-vercel-ip-country') ||
    headers.get('cf-ipcountry') ||
    undefined
  const region = headers.get('x-vercel-ip-country-region') || undefined
  const latitude = headers.get('x-vercel-ip-latitude') || undefined
  const longitude = headers.get('x-vercel-ip-longitude') || undefined
  const timezone = headers.get('x-vercel-ip-timezone') || undefined

  const country = countryCode
    ? COUNTRY_NAMES[countryCode.toUpperCase()] || undefined
    : undefined

  return { city, country, countryCode, region, latitude, longitude, timezone }
}

/**
 * Extract geolocation from an object with a `headers` property (e.g., NextRequest).
 * Mirrors the signature pattern of `userAgent({ headers })`.
 */
export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

/**
 * Check if a Geo object's countryCode is in the given list of regions.
 * Comparison is case-insensitive.
 */
export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (!geoData.countryCode) return false
  const code = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

/**
 * Calculate Haversine distance in kilometers between two lat/lon points.
 */
export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth radius in km
  const toRad = (deg: number) => (deg * Math.PI) / 180

  const dLat = toRad(parseFloat(lat2) - parseFloat(lat1))
  const dLon = toRad(parseFloat(lon2) - parseFloat(lon1))
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(parseFloat(lat1))) *
      Math.cos(toRad(parseFloat(lat2))) *
      Math.sin(dLon / 2) *
      Math.sin(dLon / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
  return R * c
}
```

Key decisions:
- `Geo` is exported as an `interface` (not a type alias) — consistent with how `UserAgent` is defined (though that one isn't exported)
- `geoFromHeaders` is the core logic; `geo` delegates to it (mirrors `userAgentFromString` / `userAgent` pattern)
- `headers.get()` returns `null` for missing headers, so we use `|| undefined` to convert to `undefined`
- Country name lookup uses `toUpperCase()` to normalize the code
- No external dependencies needed — pure TypeScript

---

