    assert.strictEqual(result.country, name, `Expected ${name} for code ${code}`)
  }
  console.log('✓ Country name lookup for all 10 codes')
}

// Test unknown country code returns undefined country name
{
  const headers = makeHeaders({ 'x-vercel-ip-country': 'ZZ' })
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'ZZ')
  assert.strictEqual(result.country, undefined)
  console.log('✓ Unknown country code returns undefined country name')
}

// Test isInRegion() with matching regions
{
  const geoData = { countryCode: 'US', country: 'United States' }
  assert.strictEqual(isInRegion(geoData, ['US', 'CA', 'GB']), true)
  console.log('✓ isInRegion() matches correctly')
}

// Test isInRegion() with non-matching regions
{
  const geoData = { countryCode: 'JP', country: 'Japan' }
  assert.strictEqual(isInRegion(geoData, ['US', 'CA', 'GB']), false)
  console.log('✓ isInRegion() rejects non-matching regions')
}

// Test isInRegion() case-insensitive comparison
{
  const geoData = { countryCode: 'us', country: 'United States' }
  assert.strictEqual(isInRegion(geoData, ['US', 'CA']), true)

  const geoData2 = { countryCode: 'US' }
  assert.strictEqual(isInRegion(geoData2, ['us', 'ca']), true)
  console.log('✓ isInRegion() case-insensitive comparison')
}

// Test isInRegion() with missing countryCode
{
  const geoData = {}
  assert.strictEqual(isInRegion(geoData, ['US', 'CA']), false)
  console.log('✓ isInRegion() returns false for missing countryCode')
}

// Test geoDistance() - New York to London (~5570 km)
{
